  d.innerHTML='<label class="block text-sm font-medium text-cream-900 mb-2">I want to</label><div class="grid grid-cols-2 sm:grid-cols-3 gap-2"><label class="flex items-center gap-2 p-3 rounded-xl border-2 border-cream-400 cursor-pointer hover:border-caramel-500 has-[:checked]:border-caramel-500 has-[:checked]:bg-caramel-500/5"><input type="radio" name="regRole" value="buyer" class="accent-caramel-500" checked><i class="fas fa-shopping-bag text-caramel-500"></i><span class="text-sm font-medium">Shop</span></label><label class="flex items-center gap-2 p-3 rounded-xl border-2 border-cream-400 cursor-pointer hover:border-sage-500 has-[:checked]:border-sage-500 has-[:checked]:bg-sage-500/5"><input type="radio" name="regRole" value="seller" class="accent-sage-500"><i class="fas fa-store text-sage-500"></i><span class="text-sm font-medium">Sell</span></label><label class="flex items-center gap-2 p-3 rounded-xl border-2 border-cream-400 cursor-pointer hover:border-gold-500 has-[:checked]:border-gold-500 has-[:checked]:bg-gold-500/5"><input type="radio" name="regRole" value="rider" class="accent-gold-500"><i class="fas fa-motorcycle text-gold-500"></i><span class="text-sm font-medium">Deliver</span></label><label class="flex items-center gap-2 p-3 rounded-xl border-2 border-cream-400 cursor-pointer hover:border-cream-800 has-[:checked]:border-cream-800 has-[:checked]:bg-cream-800/5"><input type="radio" name="regRole" value="provider" class="accent-cream-800"><i class="fas fa-concierge-bell text-cream-800"></i><span class="text-sm font-medium">Offer Services</span></label><label class="flex items-center gap-2 p-3 rounded-xl border-2 border-cream-400 cursor-pointer hover:border-terracotta-500 has-[:checked]:border-terracotta-500 has-[:checked]:bg-terracotta-500/5"><input type="radio" name="regRole" value="admin" class="accent-terracotta-500"><i class="fas fa-shield-alt text-terracotta-500"></i><span class="text-sm font-medium">Site Admin</span></label></div>';
